function LCpWebReq:RequestWeb()
    if self._isModal then GF.StartWaitMask() end

    local urlSuffix = self._reqParams
    urlSuffix = LUtil.MakeB64SendData(urlSuffix)
    LxHttpHelper.DoWebRequestURL(true, self._url , urlSuffix, function(ret, result, url)
        if self:IsDestroy() then return end

        if self._isModal then GF.StopWait() end

        if LOG_INFO_ENABLED then
            LXFW.LxLog.WEB(result)
